import React, { useState } from 'react';
import accessService from '../services/accessService';
import { useParams, useNavigate } from 'react-router-dom';
import { GoogleMap, LoadScript, Marker } from '@react-google-maps/api';
function GrantAccess(){
  const { fileId } = useParams();
  const [userEmail,setUserEmail]=useState(''); const [role,setRole]=useState('read');
  const [expiry,setExpiry]=useState(''); const [location,setLocation]=useState(null);
  const navigate=useNavigate();
  const submit = async(e)=>{ e.preventDefault(); try{ await accessService.grant({ fileId, userEmail, role, expiry_time: expiry, geo_lat: location?location.lat:null, geo_lon: location?location.lng:null }); alert('Granted'); navigate('/dashboard'); }catch(e){ alert('Failed'); } };
  const defaultCenter = { lat: 18.5204, lng:73.8567 };
  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold mb-4">Grant Access for File ID: {fileId}</h2>
      <form onSubmit={submit} className="space-y-3">
        <input required placeholder="User Email" value={userEmail} onChange={e=>setUserEmail(e.target.value)} className="w-full p-2 border rounded"/>
        <select value={role} onChange={e=>setRole(e.target.value)} className="w-full p-2 border rounded">
          <option value="read">Read</option><option value="write">Write</option><option value="download">Download</option><option value="share">Share</option>
        </select>
        <input type="datetime-local" value={expiry} onChange={e=>setExpiry(e.target.value)} className="w-full p-2 border rounded"/>
        <div>
          <LoadScript googleMapsApiKey="YOUR_GOOGLE_MAPS_API_KEY">
            <GoogleMap mapContainerStyle={{height:'300px', width:'100%'}} center={defaultCenter} zoom={10} onClick={e=>setLocation({lat:e.latLng.lat(), lng:e.latLng.lng()})}>
              {location && <Marker position={location} />}
            </GoogleMap>
          </LoadScript>
        </div>
        <button className="bg-green-600 text-white px-4 py-2 rounded">Grant Access</button>
      </form>
    </div>
  );
}
export default GrantAccess;
